116→    const queryString = params.toString();
117→    const url = `/api/vulnerabilities/current${queryString ? `?${queryString}` : ''}`;
118→
119→    const response = await authenticatedGet(url);
120→
121→    if (!response.ok) {
122→        throw new Error(`Failed to fetch vulnerabilities: ${response.status}`);
123→    }
124→
125→    return await response.json();
126→}
