300→/**
301→ * Cleanup Result interface for duplicate vulnerability cleanup
302→ * Feature: Vulnerability Duplicate Cleanup
303→ */
304→export interface VulnerabilityCleanupResult {
305→    totalScanned: number;
306→    duplicatesFound: number;
307→    duplicatesRemoved: number;
308→    uniqueVulnerabilitiesRemaining: number;
309→    message: string;
310→}
