312→/**
313→ * Cleanup duplicate vulnerabilities (ADMIN only)
314→ *
315→ * Removes duplicate vulnerabilities from the database.
316→ * A duplicate is defined as:
317→ * - Same asset ID
318→ * - Same vulnerability ID (CVE)
319→ * - Same scan timestamp
320→ *
321→ * The operation keeps the oldest record (lowest ID) and deletes the rest.
322→ * This operation is idempotent and can be safely called multiple times.
323→ *
324→ * @returns VulnerabilityCleanupResult with statistics
325→ */
326→export async function cleanupDuplicateVulnerabilities(): Promise<VulnerabilityCleanupResult> {
327→    const response = await authenticatedPost('/api/vulnerabilities/cleanup-duplicates', null);
328→
329→    if (!response.ok) {
330→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
331→        throw new Error(errorData.error || `Failed to cleanup duplicates: ${response.status}`);
332→    }
333→
334→    return await response.json();
335→}
