337→// ==================== Export Job Types ====================
338→
339→export interface ExportJob {
340→    jobId: string;
341→    status: 'PENDING' | 'PROCESSING' | 'COMPLETED' | 'FAILED' | 'CANCELLED' | 'EXPIRED';
342→    exportType: string;
343→    progressPercent: number;
344→    totalItems: number;
345→    processedItems: number;
346→    fileName: string | null;
347→    fileSizeBytes: number | null;
348→    errorMessage: string | null;
349→    createdAt: string;
350→    startedAt: string | null;
351→    completedAt: string | null;
352→    isDownloadable: boolean;
353→    isRunning: boolean;
354→}
355→
356→export interface StartExportResponse {
357→    jobId: string;
358→    message: string;
359→    status: string;
360→}
361→
362→/**
363→ * Start a vulnerability export job
364→ * Feature: Vulnerability Export Performance Optimization - Background Job Pattern
365→ *
366→ * Creates a background export job and returns immediately with the job ID.
367→ * Use pollExportStatus() to track progress.
368→ *
369→ * @returns StartExportResponse with job ID
370→ */
371→export async function startVulnerabilityExport(): Promise<StartExportResponse> {
372→    const response = await authenticatedPost('/api/vulnerabilities/export', null);
373→
374→    if (!response.ok) {
375→        if (response.status === 429) {
376→            const errorData = await response.json().catch(() => ({ error: 'Rate limit exceeded' }));
377→            throw new Error(errorData.error || 'You already have an export in progress. Please wait.');
378→        }
379→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
380→        throw new Error(errorData.error || `Failed to start export: ${response.status}`);
381→    }
382→
383→    return await response.json();
384→}
385→
386→/**
387→ * Get export job status
388→ *
389→ * @param jobId Job ID from startVulnerabilityExport()
390→ * @returns ExportJob with current status and progress
391→ */
392→export async function getExportJobStatus(jobId: string): Promise<ExportJob> {
393→    const response = await authenticatedGet(`/api/vulnerabilities/export/${jobId}/status`);
394→
395→    if (!response.ok) {
396→        if (response.status === 404) {
397→            throw new Error('Export job not found');
398→        }
399→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
400→        throw new Error(errorData.error || `Failed to get export status: ${response.status}`);
401→    }
402→
403→    return await response.json();
404→}
405→
406→/**
407→ * Download completed export file
408→ *
409→ * @param jobId Job ID of completed export
410→ */
411→export async function downloadExportFile(jobId: string): Promise<void> {
412→    const response = await authenticatedGet(`/api/vulnerabilities/export/${jobId}/download`);
413→
414→    if (!response.ok) {
415→        if (response.status === 400) {
416→            const errorData = await response.json().catch(() => ({ error: 'Export not ready' }));
417→            throw new Error(errorData.error || 'Export is not ready for download');
418→        }
419→        throw new Error(`Failed to download export: ${response.status}`);
420→    }
421→
422→    // Get the blob from response
423→    const blob = await response.blob();
424→
425→    // Extract filename from Content-Disposition header, fallback to default
426→    const contentDisposition = response.headers.get('Content-Disposition');
427→    const filenameMatch = contentDisposition?.match(/filename="?([^"]+)"?/);
428→    const filename = filenameMatch?.[1] || `vulnerabilities_export_${new Date().toISOString().split('T')[0]}.xlsx`;
429→
430→    // Trigger download
431→    const url = URL.createObjectURL(blob);
432→    const a = document.createElement('a');
433→    a.href = url;
434→    a.download = filename;
435→    document.body.appendChild(a);
436→    a.click();
437→    document.body.removeChild(a);
438→    URL.revokeObjectURL(url);
439→}
440→
441→/**
442→ * Cancel a running export job
443→ *
444→ * @param jobId Job ID to cancel
445→ */
446→export async function cancelExportJob(jobId: string): Promise<void> {
447→    const response = await authenticatedDelete(`/api/vulnerabilities/export/${jobId}`);
448→
449→    if (!response.ok && response.status !== 204) {
450→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
451→        throw new Error(errorData.error || `Failed to cancel export: ${response.status}`);
452→    }
453→}
454→
455→/**
456→ * Reset stuck export jobs
457→ * Use this when exports get stuck in PENDING/PROCESSING status
458→ *
459→ * @returns Number of jobs reset
460→ */
461→export async function resetStuckExportJobs(): Promise<{ message: string; resetCount: number }> {
462→    const response = await authenticatedPost('/api/vulnerabilities/export/reset', null);
463→
464→    if (!response.ok) {
465→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
466→        throw new Error(errorData.error || `Failed to reset stuck exports: ${response.status}`);
467→    }
468→
469→    return await response.json();
470→}
471→
472→/**
473→ * Export vulnerabilities with progress tracking
474→ * Feature: Vulnerability Export Performance Optimization - Background Job Pattern
475→ *
476→ * This is the main function to use for exporting. It:
477→ * 1. Starts the export job
478→ * 2. Polls for progress (calls onProgress callback)
479→ * 3. Downloads the file when complete
480→ *
481→ * @param onProgress Optional callback for progress updates
482→ * @returns Promise that resolves when download completes
483→ */
484→export async function exportVulnerabilitiesServerSide(
485→    onProgress?: (job: ExportJob) => void
486→): Promise<void> {
487→    // Start the export job
488→    const startResponse = await startVulnerabilityExport();
489→    const jobId = startResponse.jobId;
490→
491→    // Poll for status
492→    const pollInterval = 2000; // 2 seconds
493→    const maxPolls = 300; // 10 minutes max
494→    let polls = 0;
495→
496→    while (polls < maxPolls) {
497→        const job = await getExportJobStatus(jobId);
498→
499→        // Call progress callback
500→        if (onProgress) {
501→            onProgress(job);
502→        }
503→
504→        // Check if done
505→        if (job.status === 'COMPLETED') {
506→            // Download the file
507→            await downloadExportFile(jobId);
508→            return;
509→        }
510→
511→        if (job.status === 'FAILED') {
512→            throw new Error(job.errorMessage || 'Export failed');
513→        }
514→
515→        if (job.status === 'CANCELLED') {
516→            throw new Error('Export was cancelled');
517→        }
518→
519→        if (job.status === 'EXPIRED') {
520→            throw new Error('Export file has expired');
521→        }
522→
523→        // Wait before next poll
524→        await new Promise(resolve => setTimeout(resolve, pollInterval));
525→        polls++;
526→    }
527→
528→    throw new Error('Export timed out. Please try again.');
529→}
