                        <small className="text-muted ms-2">(ID: {exception.assetId})</small>
                    </>
                ) : exception.exceptionType === 'CVE' ? (
                    <>
                        <code>{exception.targetValue}</code>
                        {exception.assetName ? (
                            <small className="text-muted ms-2">
                                <i className="bi bi-server me-1"></i>
                                {exception.assetName}
                            </small>
                        ) : (
                            <small className="text-muted ms-2">(all systems)</small>
                        )}
                    </>
                ) : (
                    <code>{exception.targetValue}</code>
                )}
            </dd>

            {exception.affectedVulnerabilityCount != null && (
                <>
                    <dt className="col-sm-3">Affected</dt>
                    <dd className="col-sm-9">
                        <span className={`badge ${
                            exception.affectedVulnerabilityCount === 0 ? 'bg-secondary' :
                            exception.affectedVulnerabilityCount < 10 ? 'bg-success' :
                            exception.affectedVulnerabilityCount < 50 ? 'bg-warning text-dark' :
                            'bg-danger'
                        }`}>
                            {exception.affectedVulnerabilityCount}
                            {exception.affectedVulnerabilityCount === 1 ? ' vulnerability' : ' vulnerabilities'}
                        </span>
                    </dd>
                </>
            )}

            <dt className="col-sm-3">Created By</dt>
            <dd className="col-sm-9">{exception.createdBy}</dd>
        </dl>
    </div>
)}

